module up_down_counter(
    input obf_clk,
    input rst,
    input enable,
    input mode,
    output reg [7:0] count
);

always@(posedge obf_clk)
begin
  if(rst)
    count <= 0;
  else if(enable)
  begin
    if(mode)
      count <= count + 1;
    else
      count <= count - 1;
  end
end

endmodule
